-- Магические предметы SRD 5.1
INSERT INTO loot_items (name, type, rarity, requires_attunement, weight, cost_gp, description, properties, is_homebrew) VALUES

-- ЗЕЛЬЯ (расходуемые: common 50 / uncommon 150 / rare 300 / very_rare 1000 / legendary 5000)
('Зелье лечения', 'potion', 'common', false, 0.5, 50, 'Вы восстанавливаете 2d4+2 HP при употреблении этого зелья. Зелье светится красным и пахнет ягодами.', '["Восстановление: 2d4+2 HP"]', false),
('Зелье усиленного лечения', 'potion', 'uncommon', false, 0.5, 150, 'Вы восстанавливаете 4d4+4 HP при употреблении этого зелья. Его красный цвет насыщеннее, чем у обычного зелья лечения.', '["Восстановление: 4d4+4 HP"]', false),
('Зелье превосходного лечения', 'potion', 'rare', false, 0.5, 300, 'Вы восстанавливаете 8d4+8 HP при употреблении этого зелья. Тёмно-красный цвет.', '["Восстановление: 8d4+8 HP"]', false),
('Зелье наивысшего лечения', 'potion', 'very_rare', false, 0.5, 1000, 'Вы восстанавливаете 10d4+20 HP при употреблении этого зелья. Почти чёрный красный цвет.', '["Восстановление: 10d4+20 HP"]', false),
('Зелье яда', 'potion', 'common', false, 0.5, 50, 'При употреблении или применении к оружию: существо проходит спасбросок Телосложения СЛ 10 или получает 3d6 ядовитого урона и отравлено на 1 час.', '["Яд: 3d6 ядовитого","Отравление 1 час"]', false),
('Зелье скорости', 'potion', 'very_rare', false, 0.5, 1500, 'При употреблении вы получаете эффект заклинания «Ускорение» на 1 минуту (без концентрации).', '["Ускорение: 1 минута","Без концентрации"]', false),
('Зелье полёта', 'potion', 'very_rare', false, 0.5, 1000, 'При употреблении вы получаете скорость полёта 60 фт. на 1 час.', '["Полёт 60 фт.","Длительность: 1 час"]', false),
('Зелье невидимости', 'potion', 'very_rare', false, 0.5, 1000, 'При употреблении вы становитесь невидимым на 1 час. Эффект заканчивается если вы атакуете или накладываете заклинание.', '["Невидимость: 1 час"]', false),
('Зелье героизма', 'potion', 'uncommon', false, 0.5, 150, 'На 1 час вы получаете 10 временных HP и эффект «Благославения» (без концентрации).', '["10 временных HP","Благославение: 1 час"]', false),
('Зелье силы великана', 'potion', 'uncommon', false, 0.5, 150, 'При употреблении ваша Сила становится 21 на 1 час.', '["Сила 21: 1 час"]', false),

-- ОРУЖИЕ (постоянные: uncommon 400 / rare 2000 / very_rare 10000)
('Длинный меч +1', 'weapon', 'uncommon', false, 3, 400, 'Магический длинный меч с бонусом +1 к броскам атаки и урона. Рукоять украшена серебряной нитью.', '["+1 к атаке и урону","Рубящий/Колющий: 1d8/1d10"]', false),
('Длинный меч +2', 'weapon', 'rare', true, 3, 2000, 'Мощный магический длинный меч с бонусом +2 к броскам атаки и урона.', '["+2 к атаке и урону","Рубящий/Колющий: 1d8/1d10"]', false),
('Длинный меч +3', 'weapon', 'very_rare', true, 3, 10000, 'Легендарный длинный меч с бонусом +3 к броскам атаки и урона. Светится слабым голубым светом.', '["+3 к атаке и урону","Рубящий/Колющий: 1d8/1d10"]', false),
('Меч огня', 'weapon', 'rare', true, 3, 2500, 'Длинный или короткий меч с бонусом +1. При попадании наносит дополнительно 2d6 огненного урона. Клинок охвачен огнём, который освещает пространство 40 фт.', '["+1 к атаке","Дополнительно 2d6 огненного","Освещение 40 фт."]', false),
('Меч льда', 'weapon', 'very_rare', true, 3, 10000, 'Длинный меч с бонусом +2. При попадании наносит дополнительно 3d6 холодного урона. Клинок покрыт инеем.', '["+2 к атаке","Дополнительно 3d6 холодного"]', false),
('Кинжал яда', 'weapon', 'uncommon', true, 1, 400, 'Этот кинжал с бонусом +1 имеет желобок для яда. Один раз в день вы можете смазать клинок ядом (3d6 ядовитого, спасбросок СЛ 13).', '["+1 к атаке","1/день: яд 3d6","Колющий: 1d4"]', false),
('Лук охотника', 'weapon', 'rare', true, 2, 2000, 'Длинный лук с бонусом +1. Один раз в день вы можете выбрать вид существа — следующие 24 часа атаки против них наносят дополнительно 3d6.', '["+1 к атаке","1/день: +3d6 против вида"]', false),
('Копьё дракона', 'weapon', 'very_rare', true, 6, 12000, 'Копьё с бонусом +3. При попадании по дракону наносит дополнительно 3d6. Преимущество к спасброскам от Ужасающего присутствия драконов.', '["+3 к атаке","vs Дракон: +3d6","Защита от Ужаса дракона"]', false),

-- ДОСПЕХИ (постоянные: rare 2000 / very_rare 10000 / legendary 50000)
('Кольчуга +1', 'armor', 'rare', false, 55, 2000, 'Кольчуга с бонусом +1 к КД (итого КД 16+1=17). Выглядит как обычная, но блестит ярче.', '["КД 17","Нет помехи к Скрытности"]', false),
('Пластинчатый доспех +2', 'armor', 'very_rare', false, 65, 10000, 'Пластинчатый доспех с бонусом +2 к КД (итого КД 18+2=20). Тяжёлый доспех, покрытый зачарованными пластинами.', '["КД 20","Нет помехи к Скрытности"]', false),
('Доспех неуязвимости', 'armor', 'legendary', true, 65, 50000, 'Пластинчатый доспех с бонусом +3. Раз в сутки вы можете стать невосприимчивым ко всему немагическому урону на 10 минут.', '["КД 21","1/сутки: Иммунитет к немагическому урону"]', false),
('Щит +2', 'armor', 'rare', false, 6, 1500, 'Щит с бонусом +2 к КД (итого +4 от щита).', '["КД +4 (обычно +2)"]', false),
('Щит отражения заклинаний', 'armor', 'very_rare', true, 6, 12000, 'Щит с бонусом +2 к КД и спасброскам. Раз в сутки вы можете отразить заклинание обратно в заклинателя.', '["КД +4","Спасброски +2","1/сутки: Отражение заклинания"]', false),

-- КОЛЬЦА (постоянные: uncommon 400 / rare 2000 / very_rare 10000 / legendary 50000)
('Кольцо защиты', 'ring', 'uncommon', true, 0, 400, 'Кольцо даёт бонус +1 к КД и спасброскам, пока вы его носите.', '["+1 к КД","+1 к спасброскам"]', false),
('Кольцо регенерации', 'ring', 'very_rare', true, 0, 10000, 'Нося это кольцо, вы восстанавливаете 1d6 HP каждые 10 минут, если имеете хотя бы 1 HP.', '["Регенерация: 1d6/10 мин"]', false),
('Кольцо невидимости', 'ring', 'legendary', true, 0, 50000, 'Действием вы можете стать невидимым. Оставайтесь невидимым пока не атакуете или не накладываете заклинание.', '["Невидимость по желанию"]', false),
('Кольцо свободы', 'ring', 'rare', true, 0, 2000, 'Нося это кольцо, вы иммунны к состоянию «обездвижен» и к заклинаниям, ограничивающим ваше передвижение. Вы также можете двигаться и выбираться из труднопроходимой местности нормальной ценой.', '["Иммунитет к обездвиживанию","Нормальное движение в труднопроходимой местности"]', false),
('Кольцо заклинания', 'ring', 'rare', true, 0, 1500, 'Это кольцо содержит заклинание (определяется при нахождении). Его можно использовать 1d6+1 раз. Для использования: действием активируйте кольцо.', '["Хранит заклинание (1d6+1 зарядов)"]', false),

-- ЧУДЕСНЫЕ ПРЕДМЕТЫ (постоянные: uncommon 400 / rare 2000–3000 / very_rare 8000–12000 / legendary 50000)
('Мешок хранения', 'wondrous', 'uncommon', false, 0.5, 400, 'Этот тканевый мешок весит 15 фунтов и вмещает до 500 фунтов вещей, не превышающих 64 куб. фута. Предметы внутри не весят ничего, мешок всегда кажется пустым.', '["Вместимость: 500 фунтов / 64 куб.фт","Предметы не весят ничего"]', false),
('Волшебный плащ', 'wondrous', 'uncommon', true, 1, 400, 'Пока вы носите этот плащ, вы получаете +1 к КД и спасброскам. При использовании заклинания «Отклонение» вы можете потратить реакцию, чтобы получить +5 к КД.', '["+1 к КД и спасброскам","Реакция: +5 КД против одной атаки"]', false),
('Сапоги скорости', 'wondrous', 'rare', true, 1, 2500, 'Пока вы носите эти сапоги, вы можете бонусным действием щёлкнуть каблуками. Ваша скорость удваивается и вы получаете +2 к КД на 10 минут. 1 раз до отдыха.', '["1/длинный отдых: Скорость x2, +2 КД на 10 мин."]', false),
('Сапоги эльфийского хода', 'wondrous', 'uncommon', true, 1, 400, 'Ваша скорость увеличивается на 30 фт. Вы совершаете с преимуществом проверки Ловкости (Скрытность). Вы не оставляете следов.', '["Скорость +30 фт","Скрытность с преимуществом","Нет следов"]', false),
('Головной убор интеллекта', 'wondrous', 'rare', true, 1, 2500, 'Пока вы носите этот шлем, ваш показатель Интеллекта становится 19. Не действует если ваш Интеллект уже 19 или выше.', '["Интеллект 19"]', false),
('Пояс силы великана', 'wondrous', 'very_rare', true, 1, 12000, 'Пока вы носите этот пояс, ваша Сила становится 29. Не действует если ваша Сила уже 29 или выше.', '["Сила 29"]', false),
('Перчатки огра силы', 'wondrous', 'uncommon', true, 0.5, 400, 'Пока вы носите эти перчатки, ваша Сила становится 19.', '["Сила 19"]', false),
('Амулет здоровья', 'wondrous', 'rare', true, 0.5, 2500, 'Пока вы носите этот амулет, ваше Телосложение становится 19.', '["Телосложение 19"]', false),
('Крылья полёта', 'wondrous', 'very_rare', true, 1, 12000, 'Пока вы носите эту мантию, вы получаете скорость полёта 60 фт. Крылья появляются из-под мантии.', '["Полёт 60 фт.","Постоянный эффект"]', false),
('Магический шар', 'wondrous', 'very_rare', true, 1, 8000, 'Зеркальный шар, парящий на 1 фт. Вы можете сфокусироваться на нём как на фокусировке заклинателя. Вы можете использовать шар для визуализации удалённых мест (как «Ясновидение»).', '["Фокус заклинателя","1/день: Ясновидение"]', false),
('Куб силы', 'wondrous', 'legendary', true, 0.5, 50000, 'Этот 3-дюймовый куб имеет 36 зарядов. Каждая грань производит определённый эффект при активации. Эффекты варьируются от создания стены до потребления заклинательных ячеек.', '["36 зарядов","6 различных эффектов на гранях"]', false);
